-- ============================================================
-- Migration Metadata Tables: Oracle 11.2 XE -> Oracle 21c
-- 생성일: 2026-04-15
-- 대상: NEXT_MIG_INFO, NEXT_MIG_INFO_DTL, NEXT_MIG_LOG
-- 실행 계정: 해당 스키마 소유자 (scott 또는 동등 권한)
-- ============================================================

-- 기존 테이블 삭제 (FK 역순)
BEGIN EXECUTE IMMEDIATE 'DROP TABLE NEXT_MIG_LOG CASCADE CONSTRAINTS PURGE'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DROP TABLE NEXT_MIG_INFO_DTL CASCADE CONSTRAINTS PURGE'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DROP TABLE NEXT_MIG_INFO CASCADE CONSTRAINTS PURGE'; EXCEPTION WHEN OTHERS THEN NULL; END;
/

BEGIN EXECUTE IMMEDIATE 'DROP SEQUENCE MAPPING_RULES_SEQ'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DROP SEQUENCE MAPPING_RULE_DETAIL_SEQ'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DROP SEQUENCE MAP_DTL_SEQ'; EXCEPTION WHEN OTHERS THEN NULL; END;
/
BEGIN EXECUTE IMMEDIATE 'DROP SEQUENCE MIGRATION_LOG_SEQ'; EXCEPTION WHEN OTHERS THEN NULL; END;
/

-- ============================================================
-- 1. CREATE TABLES
-- ============================================================

CREATE TABLE NEXT_MIG_INFO (
    MAP_ID           NUMBER            NOT NULL,
    MAP_TYPE         VARCHAR2(20),
    FR_TABLE         VARCHAR2(200),
    TO_TABLE         VARCHAR2(200),
    USE_YN           CHAR(1)           DEFAULT 'Y',
    TARGET_YN        VARCHAR2(100),
    PRIORITY         NUMBER,
    MIG_SQL          CLOB,
    VERIFY_SQL       CLOB,
    STATUS           VARCHAR2(20),
    BATCH_CNT        NUMBER            DEFAULT 0,
    CORRECT_SQL      CLOB,
    USER_EDITED      CHAR(1)           DEFAULT 'N',
    UPD_TS           TIMESTAMP         DEFAULT CURRENT_TIMESTAMP,
    ELAPSED_SECONDS  NUMBER            DEFAULT 0,
    RETRY_COUNT      NUMBER            DEFAULT 0,
    CREATED_AT       TIMESTAMP         DEFAULT CURRENT_TIMESTAMP,
    DDL_SQL          CLOB,
    CONSTRAINT NEXT_MIG_INFO_PK PRIMARY KEY (MAP_ID)
);
/

CREATE TABLE NEXT_MIG_INFO_DTL (
    MAP_DTL  NUMBER         NOT NULL,
    MAP_ID   NUMBER,
    FR_COL   VARCHAR2(200),
    TO_COL   VARCHAR2(200),
    CONSTRAINT NEXT_MIG_INFO_DTL_PK PRIMARY KEY (MAP_DTL),
    CONSTRAINT FK_MAPPING_RULE FOREIGN KEY (MAP_ID)
        REFERENCES NEXT_MIG_INFO(MAP_ID)
);
/

CREATE TABLE NEXT_MIG_LOG (
    LOG_ID       NUMBER            NOT NULL,
    MAP_ID       NUMBER,
    MIG_KIND     VARCHAR2(20),
    LOG_TYPE     VARCHAR2(20),
    LOG_LEVEL    VARCHAR2(20),
    STEP_NAME    VARCHAR2(50),
    STATUS       VARCHAR2(20),
    MESSAGE      VARCHAR2(4000),
    RETRY_COUNT  NUMBER            DEFAULT 0,
    CREATED_AT   TIMESTAMP         DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT NEXT_MIG_LOG_PK PRIMARY KEY (LOG_ID)
);
/

-- ============================================================
-- 2. INSERT NEXT_MIG_INFO (CLOB 포함, PL/SQL 블록 사용)
-- ============================================================

-- MAP_ID = 1 (TGT_EMP)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO TGT_EMP (EMP_ID, EMAIL, NAME, HIRE_DATE, JOB_ID, SALARY)
SELECT 
  EMPLOYEE_ID, 
  EMAIL, 
  FIRST_NAME || '' '' || LAST_NAME, 
  HIRE_DATE, 
  JOB_ID, 
  SALARY
FROM EMPLOYEES;';
    v_verify := 'SELECT SUM(CASE WHEN src.EMP_ID IS NULL THEN 1 ELSE 0 END) + SUM(CASE WHEN tgt.EMP_ID IS NULL THEN 1 ELSE 0 END) + SUM(CASE WHEN src.EMAIL <> tgt.EMAIL THEN 1 ELSE 0 END) + SUM(CASE WHEN src.NAME <> tgt.NAME THEN 1 ELSE 0 END) + SUM(CASE WHEN src.HIRE_DATE <> tgt.HIRE_DATE THEN 1 ELSE 0 END) + SUM(CASE WHEN src.JOB_ID <> tgt.JOB_ID THEN 1 ELSE 0 END) + SUM(CASE WHEN NVL(src.SALARY, -1) <> NVL(tgt.SALARY, -1) THEN 1 ELSE 0 END) AS DIFF
FROM (
  SELECT 
    EMPLOYEE_ID AS EMP_ID,
    EMAIL,
    FIRST_NAME || '' '' || LAST_NAME AS NAME,
    HIRE_DATE,
    JOB_ID,
    SALARY
  FROM EMPLOYEES
) src
FULL OUTER JOIN TGT_EMP tgt
ON src.EMP_ID = tgt.EMP_ID;';
    v_correct := NULL;
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        1, 'SIMPLE', 'EMPLOYEES', 'TGT_EMP',
        'N', 'Y', 1,
        v_mig, v_verify,
        'PASS', 4, v_correct, 'N',
        TO_TIMESTAMP('2026-04-15 21:23:50.517000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 5, 1,
        TO_TIMESTAMP('2026-04-14 10:41:47.183000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

-- MAP_ID = 3 (TGT_EMP_JOB)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO TGT_EMP_JOB (EMP_ID, EMP_NAME, SALARY, JOB_TITLE)
SELECT
    E.EMPLOYEE_ID,
    E.FIRST_NAME || '' '' || E.LAST_NAME,
    E.SALARY,
    J.JOB_TITLE
FROM
    EMPLOYEES E
JOIN
    JOBS J ON E.JOB_ID = J.JOB_ID;';
    v_verify := 'SELECT SUM(CASE WHEN SRC.EMP_ID IS NULL THEN 1 ELSE 0 END) + SUM(CASE WHEN TGT.EMP_ID IS NULL THEN 1 ELSE 0 END) + SUM(CASE WHEN NVL(SRC.EMP_NAME, ''X'') <> NVL(TGT.EMP_NAME, ''X'') THEN 1 ELSE 0 END) + SUM(CASE WHEN NVL(SRC.SALARY, -99999999.99) <> NVL(TGT.SALARY, -99999999.99) THEN 1 ELSE 0 END) + SUM(CASE WHEN NVL(SRC.JOB_TITLE, ''X'') <> NVL(TGT.JOB_TITLE, ''X'') THEN 1 ELSE 0 END) AS DIFF
FROM (
    SELECT
        E.EMPLOYEE_ID AS EMP_ID,
        E.FIRST_NAME || '' '' || E.LAST_NAME AS EMP_NAME,
        E.SALARY AS SALARY,
        J.JOB_TITLE AS JOB_TITLE
    FROM
        EMPLOYEES E
    JOIN
        JOBS J ON E.JOB_ID = J.JOB_ID
) SRC
FULL OUTER JOIN (
    SELECT
        EMP_ID,
        EMP_NAME,
        SALARY,
        JOB_TITLE
    FROM
        TGT_EMP_JOB
) TGT ON SRC.EMP_ID = TGT.EMP_ID;';
    v_correct := NULL;
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        3, 'COMPLEX', 'EMPLOYEES E JOIN JOBS J ON E.JOB_ID = J.JOB_ID', 'TGT_EMP_JOB',
        'N', 'Y', 3,
        v_mig, v_verify,
        'PASS', 2, v_correct, 'N',
        TO_TIMESTAMP('2026-04-15 21:23:56.493000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 5, 1,
        TO_TIMESTAMP('2026-04-14 10:41:47.194000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

-- MAP_ID = 101 (HR_EMP_DEPT_JOB_SNAP)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO HR_EMP_DEPT_JOB_SNAP ( EMPLOYEE_ID, FIRST_NAME, LAST_NAME, EMAIL, PHONE_NUMBER, HIRE_DATE, JOB_ID, SALARY, COMMISSION_PCT, MANAGER_ID, DEPARTMENT_ID, DEPARTMENT_NAME, DEPT_MANAGER_ID, JOB_TITLE, MANAGER_EXISTS_YN, SALARY_BAND, JOB_RANGE_STATUS, DEPT_EMP_COUNT, JOB_SALARY_RANK, DEPT_SALARY_RANK ) SELECT e.EMPLOYEE_ID, e.FIRST_NAME, e.LAST_NAME, e.EMAIL, e.PHONE_NUMBER, e.HIRE_DATE, e.JOB_ID, e.SALARY, e.COMMISSION_PCT, e.MANAGER_ID, e.DEPARTMENT_ID, d.DEPARTMENT_NAME, d.MANAGER_ID, j.JOB_TITLE, CASE WHEN e.MANAGER_ID IS NULL THEN ''NO_MANAGER'' ELSE ''HAS_MANAGER'' END AS MANAGER_EXISTS_YN, CASE WHEN e.SALARY >= 20000 THEN ''EXEC'' WHEN e.SALARY >= 12000 THEN ''HIGH'' WHEN e.SALARY >= 7000 THEN ''MID'' ELSE ''LOW'' END AS SALARY_BAND, CASE WHEN j.MAX_SALARY IS NULL THEN ''NO_JOB_RANGE'' WHEN e.SALARY > j.MAX_SALARY THEN ''ABOVE_JOB_MAX'' WHEN e.SALARY < j.MIN_SALARY THEN ''BELOW_JOB_MIN'' ELSE ''IN_JOB_RANGE'' END AS JOB_RANGE_STATUS, COUNT(*) OVER (PARTITION BY e.DEPARTMENT_ID) AS DEPT_EMP_COUNT, DENSE_RANK() OVER (PARTITION BY e.JOB_ID ORDER BY e.SALARY DESC) AS JOB_SALARY_RANK, ROW_NUMBER() OVER (PARTITION BY e.DEPARTMENT_ID ORDER BY e.SALARY DESC, e.EMPLOYEE_ID) AS DEPT_SALARY_RANK FROM EMPLOYEES e LEFT JOIN DEPARTMENTS d ON d.DEPARTMENT_ID = e.DEPARTMENT_ID LEFT JOIN JOBS j ON j.JOB_ID = e.JOB_ID';
    v_verify := 'SELECT SUM(CASE WHEN src.MANAGER_EXISTS_YN <> tgt.MANAGER_EXISTS_YN OR (src.MANAGER_EXISTS_YN IS NULL AND tgt.MANAGER_EXISTS_YN IS NOT NULL) OR (src.MANAGER_EXISTS_YN IS NOT NULL AND tgt.MANAGER_EXISTS_YN IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.SALARY_BAND <> tgt.SALARY_BAND OR (src.SALARY_BAND IS NULL AND tgt.SALARY_BAND IS NOT NULL) OR (src.SALARY_BAND IS NOT NULL AND tgt.SALARY_BAND IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.JOB_RANGE_STATUS <> tgt.JOB_RANGE_STATUS OR (src.JOB_RANGE_STATUS IS NULL AND tgt.JOB_RANGE_STATUS IS NOT NULL) OR (src.JOB_RANGE_STATUS IS NOT NULL AND tgt.JOB_RANGE_STATUS IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.DEPT_EMP_COUNT <> tgt.DEPT_EMP_COUNT OR (src.DEPT_EMP_COUNT IS NULL AND tgt.DEPT_EMP_COUNT IS NOT NULL) OR (src.DEPT_EMP_COUNT IS NOT NULL AND tgt.DEPT_EMP_COUNT IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.JOB_SALARY_RANK <> tgt.JOB_SALARY_RANK OR (src.JOB_SALARY_RANK IS NULL AND tgt.JOB_SALARY_RANK IS NOT NULL) OR (src.JOB_SALARY_RANK IS NOT NULL AND tgt.JOB_SALARY_RANK IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.DEPT_SALARY_RANK <> tgt.DEPT_SALARY_RANK OR (src.DEPT_SALARY_RANK IS NULL AND tgt.DEPT_SALARY_RANK IS NOT NULL) OR (src.DEPT_SALARY_RANK IS NOT NULL AND tgt.DEPT_SALARY_RANK IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.DEPARTMENT_NAME <> tgt.DEPARTMENT_NAME OR (src.DEPARTMENT_NAME IS NULL AND tgt.DEPARTMENT_NAME IS NOT NULL) OR (src.DEPARTMENT_NAME IS NOT NULL AND tgt.DEPARTMENT_NAME IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.DEPT_MANAGER_ID <> tgt.DEPT_MANAGER_ID OR (src.DEPT_MANAGER_ID IS NULL AND tgt.DEPT_MANAGER_ID IS NOT NULL) OR (src.DEPT_MANAGER_ID IS NOT NULL AND tgt.DEPT_MANAGER_ID IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.COMMISSION_PCT <> tgt.COMMISSION_PCT OR (src.COMMISSION_PCT IS NULL AND tgt.COMMISSION_PCT IS NOT NULL) OR (src.COMMISSION_PCT IS NOT NULL AND tgt.COMMISSION_PCT IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.DEPARTMENT_ID <> tgt.DEPARTMENT_ID OR (src.DEPARTMENT_ID IS NULL AND tgt.DEPARTMENT_ID IS NOT NULL) OR (src.DEPARTMENT_ID IS NOT NULL AND tgt.DEPARTMENT_ID IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.EMAIL <> tgt.EMAIL OR (src.EMAIL IS NULL AND tgt.EMAIL IS NOT NULL) OR (src.EMAIL IS NOT NULL AND tgt.EMAIL IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.EMPLOYEE_ID <> tgt.EMPLOYEE_ID OR (src.EMPLOYEE_ID IS NULL AND tgt.EMPLOYEE_ID IS NOT NULL) OR (src.EMPLOYEE_ID IS NOT NULL AND tgt.EMPLOYEE_ID IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.FIRST_NAME <> tgt.FIRST_NAME OR (src.FIRST_NAME IS NULL AND tgt.FIRST_NAME IS NOT NULL) OR (src.FIRST_NAME IS NOT NULL AND tgt.FIRST_NAME IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.HIRE_DATE <> tgt.HIRE_DATE OR (src.HIRE_DATE IS NULL AND tgt.HIRE_DATE IS NOT NULL) OR (src.HIRE_DATE IS NOT NULL AND tgt.HIRE_DATE IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.JOB_ID <> tgt.JOB_ID OR (src.JOB_ID IS NULL AND tgt.JOB_ID IS NOT NULL) OR (src.JOB_ID IS NOT NULL AND tgt.JOB_ID IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.LAST_NAME <> tgt.LAST_NAME OR (src.LAST_NAME IS NULL AND tgt.LAST_NAME IS NOT NULL) OR (src.LAST_NAME IS NOT NULL AND tgt.LAST_NAME IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.MANAGER_ID <> tgt.MANAGER_ID OR (src.MANAGER_ID IS NULL AND tgt.MANAGER_ID IS NOT NULL) OR (src.MANAGER_ID IS NOT NULL AND tgt.MANAGER_ID IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.PHONE_NUMBER <> tgt.PHONE_NUMBER OR (src.PHONE_NUMBER IS NULL AND tgt.PHONE_NUMBER IS NOT NULL) OR (src.PHONE_NUMBER IS NOT NULL AND tgt.PHONE_NUMBER IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.CURRENT_SALARY <> tgt.CURRENT_SALARY OR (src.CURRENT_SALARY IS NULL AND tgt.CURRENT_SALARY IS NOT NULL) OR (src.CURRENT_SALARY IS NOT NULL AND tgt.CURRENT_SALARY IS NULL) THEN 1 ELSE 0 END) + SUM(CASE WHEN src.JOB_TITLE <> tgt.JOB_TITLE OR (src.JOB_TITLE IS NULL AND tgt.JOB_TITLE IS NOT NULL) OR (src.JOB_TITLE IS NOT NULL AND tgt.JOB_TITLE IS NULL) THEN 1 ELSE 0 END) AS DIFF FROM ( SELECT e.EMPLOYEE_ID, e.FIRST_NAME, e.LAST_NAME, e.EMAIL, e.PHONE_NUMBER, e.HIRE_DATE, e.JOB_ID, e.SALARY AS CURRENT_SALARY, e.COMMISSION_PCT, e.MANAGER_ID, e.DEPARTMENT_ID, d.DEPARTMENT_NAME, d.MANAGER_ID AS DEPT_MANAGER_ID, j.JOB_TITLE, CASE WHEN e.MANAGER_ID IS NULL THEN ''NO_MANAGER'' ELSE ''HAS_MANAGER'' END AS MANAGER_EXISTS_YN, CASE WHEN e.SALARY >= 20000 THEN ''EXEC'' WHEN e.SALARY >= 12000 THEN ''HIGH'' WHEN e.SALARY >= 7000 THEN ''MID'' ELSE ''LOW'' END AS SALARY_BAND, CASE WHEN j.MAX_SALARY IS NULL THEN ''NO_JOB_RANGE'' WHEN e.SALARY > j.MAX_SALARY THEN ''ABOVE_JOB_MAX'' WHEN e.SALARY < j.MIN_SALARY THEN ''BELOW_JOB_MIN'' ELSE ''IN_JOB_RANGE'' END AS JOB_RANGE_STATUS, COUNT(e.EMPLOYEE_ID) OVER (PARTITION BY e.DEPARTMENT_ID) AS DEPT_EMP_COUNT, DENSE_RANK() OVER (PARTITION BY e.JOB_ID ORDER BY e.SALARY DESC) AS JOB_SALARY_RANK, ROW_NUMBER() OVER (PARTITION BY e.DEPARTMENT_ID ORDER BY e.SALARY DESC, e.EMPLOYEE_ID) AS DEPT_SALARY_RANK FROM EMPLOYEES e LEFT JOIN DEPARTMENTS d ON d.DEPARTMENT_ID = e.DEPARTMENT_ID LEFT JOIN JOBS j ON j.JOB_ID = e.JOB_ID ) src FULL OUTER JOIN HR_EMP_DEPT_JOB_SNAP tgt ON src.EMPLOYEE_ID = tgt.EMPLOYEE_ID AND src.JOB_ID = tgt.JOB_ID AND src.DEPARTMENT_ID = tgt.DEPARTMENT_ID';
    v_correct := NULL;
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        101, 'COMPLEX', 'EMPLOYEES e LEFT JOIN DEPARTMENTS d ON d.DEPARTMENT_ID=e.DEPARTMENT_ID LEFT JOIN JOBS j ON j.JOB_ID=e.JOB_ID', 'HR_EMP_DEPT_JOB_SNAP',
        'N', 'Y', 101,
        v_mig, v_verify,
        'FAIL', 2, v_correct, 'N',
        TO_TIMESTAMP('2026-04-15 21:24:25.497000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 28, 3,
        TO_TIMESTAMP('2026-04-15 10:18:13.805000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

-- MAP_ID = 102 (HR_DEPT_PAYROLL_ROLLUP_F)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO HR_DEPT_PAYROLL_ROLLUP_F ( DEPARTMENT_ID, DEPARTMENT_NAME, DEPT_MANAGER_ID, DEPT_PAY_BAND, JOB_DIVERSITY_BAND, DEPT_SIZE_BAND, DISTINCT_JOB_COUNT, EMP_COUNT, LAST_HIRE_DATE, MAX_SALARY, MEDIAN_SALARY, FIRST_HIRE_DATE, MIN_SALARY, AVG_SALARY, SALARY_STDDEV, LOW_SALARY_COUNT, HIGH_SALARY_COUNT, TOTAL_SALARY ) SELECT d.DEPARTMENT_ID, d.DEPARTMENT_NAME, d.MANAGER_ID AS DEPT_MANAGER_ID, CASE WHEN AVG(e.SALARY) IS NULL THEN ''N/A'' WHEN AVG(e.SALARY) >= 12000 THEN ''HIGH_PAY'' WHEN AVG(e.SALARY) >= 7000 THEN ''MID_PAY'' ELSE ''LOW_PAY'' END AS DEPT_PAY_BAND, CASE WHEN COUNT(DISTINCT e.JOB_ID) >= 4 THEN ''DIVERSE'' WHEN COUNT(DISTINCT e.JOB_ID) >= 2 THEN ''BALANCED'' ELSE ''NARROW'' END AS JOB_DIVERSITY_BAND, CASE WHEN COUNT(e.EMPLOYEE_ID) = 0 THEN ''EMPTY'' WHEN COUNT(e.EMPLOYEE_ID) >= 10 THEN ''LARGE'' WHEN COUNT(e.EMPLOYEE_ID) >= 5 THEN ''MEDIUM'' ELSE ''SMALL'' END AS DEPT_SIZE_BAND, COUNT(DISTINCT e.JOB_ID) AS DISTINCT_JOB_COUNT, COUNT(e.EMPLOYEE_ID) AS EMP_COUNT, MAX(e.HIRE_DATE) AS LAST_HIRE_DATE, MAX(e.SALARY) AS MAX_SALARY, ROUND(MEDIAN(e.SALARY), 2) AS MEDIAN_SALARY, MIN(e.HIRE_DATE) AS FIRST_HIRE_DATE, MIN(e.SALARY) AS MIN_SALARY, ROUND(AVG(e.SALARY), 2) AS AVG_SALARY, ROUND(STDDEV(e.SALARY), 2) AS SALARY_STDDEV, SUM(CASE WHEN e.SALARY < 7000 THEN 1 ELSE 0 END) AS LOW_SALARY_COUNT, SUM(CASE WHEN e.SALARY >= 12000 THEN 1 ELSE 0 END) AS HIGH_SALARY_COUNT, SUM(e.SALARY) AS TOTAL_SALARY FROM DEPARTMENTS d LEFT JOIN EMPLOYEES e ON e.DEPARTMENT_ID = d.DEPARTMENT_ID GROUP BY d.DEPARTMENT_ID, d.DEPARTMENT_NAME, d.MANAGER_ID';
    v_verify := 'SELECT SUM(CASE WHEN src.DEPT_PAY_BAND <> tgt.DEPT_PAY_BAND OR src.JOB_DIVERSITY_BAND <> tgt.JOB_DIVERSITY_BAND OR src.DEPT_SIZE_BAND <> tgt.DEPT_SIZE_BAND OR src.DISTINCT_JOB_COUNT <> tgt.DISTINCT_JOB_COUNT OR src.EMP_COUNT <> tgt.EMP_COUNT OR src.LAST_HIRE_DATE <> tgt.LAST_HIRE_DATE OR src.MAX_SALARY <> tgt.MAX_SALARY OR src.MEDIAN_SALARY <> tgt.MEDIAN_SALARY OR src.FIRST_HIRE_DATE <> tgt.FIRST_HIRE_DATE OR src.MIN_SALARY <> tgt.MIN_SALARY OR src.AVG_SALARY <> tgt.AVG_SALARY OR src.SALARY_STDDEV <> tgt.SALARY_STDDEV OR src.LOW_SALARY_COUNT <> tgt.LOW_SALARY_COUNT OR src.HIGH_SALARY_COUNT <> tgt.HIGH_SALARY_COUNT OR src.TOTAL_SALARY <> tgt.TOTAL_SALARY THEN 1 ELSE 0 END) AS DIFF FROM ( SELECT d.DEPARTMENT_ID, CASE WHEN AVG(e.SALARY) IS NULL THEN ''N/A'' WHEN AVG(e.SALARY) >= 12000 THEN ''HIGH_PAY'' WHEN AVG(e.SALARY) >= 7000 THEN ''MID_PAY'' ELSE ''LOW_PAY'' END AS DEPT_PAY_BAND, CASE WHEN COUNT(DISTINCT e.JOB_ID) >= 4 THEN ''DIVERSE'' WHEN COUNT(DISTINCT e.JOB_ID) >= 2 THEN ''BALANCED'' ELSE ''NARROW'' END AS JOB_DIVERSITY_BAND, CASE WHEN COUNT(e.EMPLOYEE_ID) = 0 THEN ''EMPTY'' WHEN COUNT(e.EMPLOYEE_ID) >= 10 THEN ''LARGE'' WHEN COUNT(e.EMPLOYEE_ID) >= 5 THEN ''MEDIUM'' ELSE ''SMALL'' END AS DEPT_SIZE_BAND, COUNT(DISTINCT e.JOB_ID) AS DISTINCT_JOB_COUNT, COUNT(e.EMPLOYEE_ID) AS EMP_COUNT, MAX(e.HIRE_DATE) AS LAST_HIRE_DATE, MAX(e.SALARY) AS MAX_SALARY, ROUND(MEDIAN(e.SALARY), 2) AS MEDIAN_SALARY, MIN(e.HIRE_DATE) AS FIRST_HIRE_DATE, MIN(e.SALARY) AS MIN_SALARY, ROUND(AVG(e.SALARY), 2) AS AVG_SALARY, ROUND(STDDEV(e.SALARY), 2) AS SALARY_STDDEV, SUM(CASE WHEN e.SALARY < 7000 THEN 1 ELSE 0 END) AS LOW_SALARY_COUNT, SUM(CASE WHEN e.SALARY >= 12000 THEN 1 ELSE 0 END) AS HIGH_SALARY_COUNT, SUM(e.SALARY) AS TOTAL_SALARY FROM DEPARTMENTS d LEFT JOIN EMPLOYEES e ON e.DEPARTMENT_ID = d.DEPARTMENT_ID GROUP BY d.DEPARTMENT_ID ) src FULL OUTER JOIN ( SELECT DEPARTMENT_ID, DEPT_PAY_BAND, JOB_DIVERSITY_BAND, DEPT_SIZE_BAND, DISTINCT_JOB_COUNT, EMP_COUNT, LAST_HIRE_DATE, MAX_SALARY, MEDIAN_SALARY, FIRST_HIRE_DATE, MIN_SALARY, AVG_SALARY, SALARY_STDDEV, LOW_SALARY_COUNT, HIGH_SALARY_COUNT, TOTAL_SALARY FROM HR_DEPT_PAYROLL_ROLLUP_F ) tgt ON src.DEPARTMENT_ID = tgt.DEPARTMENT_ID WHERE src.DEPT_PAY_BAND <> tgt.DEPT_PAY_BAND OR src.JOB_DIVERSITY_BAND <> tgt.JOB_DIVERSITY_BAND OR src.DEPT_SIZE_BAND <> tgt.DEPT_SIZE_BAND OR src.DISTINCT_JOB_COUNT <> tgt.DISTINCT_JOB_COUNT OR src.EMP_COUNT <> tgt.EMP_COUNT OR src.LAST_HIRE_DATE <> tgt.LAST_HIRE_DATE OR src.MAX_SALARY <> tgt.MAX_SALARY OR src.MEDIAN_SALARY <> tgt.MEDIAN_SALARY OR src.FIRST_HIRE_DATE <> tgt.FIRST_HIRE_DATE OR src.MIN_SALARY <> tgt.MIN_SALARY OR src.AVG_SALARY <> tgt.AVG_SALARY OR src.SALARY_STDDEV <> tgt.SALARY_STDDEV OR src.LOW_SALARY_COUNT <> tgt.LOW_SALARY_COUNT OR src.HIGH_SALARY_COUNT <> tgt.HIGH_SALARY_COUNT OR src.TOTAL_SALARY <> tgt.TOTAL_SALARY OR (src.DEPARTMENT_ID IS NULL OR tgt.DEPARTMENT_ID IS NULL)';
    v_correct := '-- [정답 패턴 힌트] NUMBER(12,2) 타입 컬럼에 저장되는 부동소수점 집계는 반드시 ROUND 처리
-- MIG_SQL 핵심 패턴:
--   ROUND(STDDEV(e.SALARY), 2) AS SALARY_STDDEV   -- ROUND 필수
--   ROUND(MEDIAN(e.SALARY), 2) AS MEDIAN_SALARY   -- ROUND 필수
--   ROUND(AVG(e.SALARY), 2)    AS AVG_SALARY       -- 이미 적용됨
-- VERIFY_SQL src_base에서도 동일하게 ROUND 적용하여 타겟과 정밀도를 맞춤
SELECT d.DEPARTMENT_ID, d.DEPARTMENT_NAME, d.MANAGER_ID,
    COUNT(e.EMPLOYEE_ID) AS EMP_COUNT,
    ROUND(AVG(e.SALARY), 2) AS AVG_SALARY,
    ROUND(STDDEV(e.SALARY), 2) AS SALARY_STDDEV,
    ROUND(MEDIAN(e.SALARY), 2) AS MEDIAN_SALARY
FROM DEPARTMENTS d
LEFT JOIN EMPLOYEES e ON e.DEPARTMENT_ID = d.DEPARTMENT_ID
GROUP BY d.DEPARTMENT_ID, d.DEPARTMENT_NAME, d.MANAGER_ID';
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        102, 'COMPLEX', 'DEPARTMENTS d LEFT JOIN EMPLOYEES e ON e.DEPARTMENT_ID=d.DEPARTMENT_ID', 'HR_DEPT_PAYROLL_ROLLUP_F',
        'N', 'Y', 102,
        v_mig, v_verify,
        'PASS', 2, v_correct, 'Y',
        TO_TIMESTAMP('2026-04-15 21:24:56.208000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 29, 3,
        TO_TIMESTAMP('2026-04-15 10:18:13.821000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

-- MAP_ID = 103 (HR_EMP_CAREER_EVENT_F)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO HR_EMP_CAREER_EVENT_F (
    EVENT_SOURCE,
    EVENT_TYPE,
    EVENT_STATUS,
    EVENT_END_DATE,
    HISTORY_GAP_DAYS,
    PREV_DEPARTMENT_ID,
    PREV_JOB_ID,
    EMP_EVENT_SEQ,
    DEPARTMENT_ID,
    EMPLOYEE_ID,
    EVENT_DATE,
    JOB_ID,
    CURRENT_SALARY
)
SELECT 
    ''CURRENT'' AS EVENT_SOURCE,
    ''CURRENT_SNAPSHOT'' AS EVENT_TYPE,
    ''OPEN'' AS EVENT_STATUS,
    CAST(NULL AS DATE) AS EVENT_END_DATE,
    CAST(NULL AS NUMBER) AS HISTORY_GAP_DAYS,
    LAG(e.DEPARTMENT_ID) OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE, ''CURRENT'') AS PREV_DEPARTMENT_ID,
    LAG(e.JOB_ID) OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE, ''CURRENT'') AS PREV_JOB_ID,
    ROW_NUMBER() OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE, ''CURRENT'') AS EMP_EVENT_SEQ,
    e.DEPARTMENT_ID,
    e.EMPLOYEE_ID,
    e.HIRE_DATE AS EVENT_DATE,
    e.JOB_ID,
    e.SALARY AS CURRENT_SALARY
FROM 
    EMPLOYEES e
UNION ALL
SELECT 
    ''HISTORY'' AS EVENT_SOURCE,
    ''JOB_HISTORY'' AS EVENT_TYPE,
    CASE WHEN jh.END_DATE IS NULL THEN ''OPEN'' ELSE ''CLOSED'' END AS EVENT_STATUS,
    jh.END_DATE AS EVENT_END_DATE,
    TRUNC(NVL(jh.END_DATE, SYSDATE) - jh.START_DATE) AS HISTORY_GAP_DAYS,
    LAG(jh.DEPARTMENT_ID) OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE, ''HISTORY'') AS PREV_DEPARTMENT_ID,
    LAG(jh.JOB_ID) OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE, ''HISTORY'') AS PREV_JOB_ID,
    ROW_NUMBER() OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE, ''HISTORY'') AS EMP_EVENT_SEQ,
    jh.DEPARTMENT_ID,
    jh.EMPLOYEE_ID,
    jh.START_DATE AS EVENT_DATE,
    jh.JOB_ID,
    CAST(NULL AS NUMBER) AS CURRENT_SALARY
FROM 
    JOB_HISTORY jh;';
    v_verify := 'SELECT 
    SUM(CASE 
        WHEN src.EVENT_SOURCE <> tgt.EVENT_SOURCE THEN 1
        WHEN src.EVENT_TYPE <> tgt.EVENT_TYPE THEN 1
        WHEN src.EVENT_STATUS <> tgt.EVENT_STATUS THEN 1
        WHEN src.EVENT_END_DATE <> tgt.EVENT_END_DATE THEN 1
        WHEN src.HISTORY_GAP_DAYS <> tgt.HISTORY_GAP_DAYS THEN 1
        WHEN src.PREV_DEPARTMENT_ID <> tgt.PREV_DEPARTMENT_ID THEN 1
        WHEN src.PREV_JOB_ID <> tgt.PREV_JOB_ID THEN 1
        WHEN src.EMP_EVENT_SEQ <> tgt.EMP_EVENT_SEQ THEN 1
        WHEN src.DEPARTMENT_ID <> tgt.DEPARTMENT_ID THEN 1
        WHEN src.EMPLOYEE_ID <> tgt.EMPLOYEE_ID THEN 1
        WHEN src.EVENT_DATE <> tgt.EVENT_DATE THEN 1
        WHEN src.JOB_ID <> tgt.JOB_ID THEN 1
        WHEN src.CURRENT_SALARY <> tgt.CURRENT_SALARY THEN 1
        ELSE 0
    END) AS DIFF
FROM (
    SELECT 
        ''CURRENT'' AS EVENT_SOURCE,
        ''CURRENT_SNAPSHOT'' AS EVENT_TYPE,
        ''OPEN'' AS EVENT_STATUS,
        CAST(NULL AS DATE) AS EVENT_END_DATE,
        CAST(NULL AS NUMBER) AS HISTORY_GAP_DAYS,
        LAG(e.DEPARTMENT_ID) OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE, ''CURRENT'') AS PREV_DEPARTMENT_ID,
        LAG(e.JOB_ID) OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE, ''CURRENT'') AS PREV_JOB_ID,
        ROW_NUMBER() OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE, ''CURRENT'') AS EMP_EVENT_SEQ,
        e.DEPARTMENT_ID,
        e.EMPLOYEE_ID,
        e.HIRE_DATE AS EVENT_DATE,
        e.JOB_ID,
        e.SALARY AS CURRENT_SALARY
    FROM 
        EMPLOYEES e
    UNION ALL
    SELECT 
        ''HISTORY'' AS EVENT_SOURCE,
        ''JOB_HISTORY'' AS EVENT_TYPE,
        CASE WHEN jh.END_DATE IS NULL THEN ''OPEN'' ELSE ''CLOSED'' END AS EVENT_STATUS,
        jh.END_DATE AS EVENT_END_DATE,
        TRUNC(NVL(jh.END_DATE, SYSDATE) - jh.START_DATE) AS HISTORY_GAP_DAYS,
        LAG(jh.DEPARTMENT_ID) OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE, ''HISTORY'') AS PREV_DEPARTMENT_ID,
        LAG(jh.JOB_ID) OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE, ''HISTORY'') AS PREV_JOB_ID,
        ROW_NUMBER() OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE, ''HISTORY'') AS EMP_EVENT_SEQ,
        jh.DEPARTMENT_ID,
        jh.EMPLOYEE_ID,
        jh.START_DATE AS EVENT_DATE,
        jh.JOB_ID,
        CAST(NULL AS NUMBER) AS CURRENT_SALARY
    FROM 
        JOB_HISTORY jh
) src
LEFT JOIN 
    HR_EMP_CAREER_EVENT_F tgt 
ON 
    src.EMPLOYEE_ID = tgt.EMPLOYEE_ID 
    AND src.EVENT_DATE = tgt.EVENT_DATE
    AND src.EVENT_SOURCE = tgt.EVENT_SOURCE
    AND src.EVENT_TYPE = tgt.EVENT_TYPE;';
    v_correct := NULL;
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        103, 'COMPLEX', '(CURRENT UNION ALL HISTORY) FROM EMPLOYEES, JOB_HISTORY', 'HR_EMP_CAREER_EVENT_F',
        'N', 'Y', 103,
        v_mig, v_verify,
        'PASS', 2, v_correct, 'N',
        TO_TIMESTAMP('2026-04-15 21:25:04.132000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 7, 1,
        TO_TIMESTAMP('2026-04-15 10:18:13.829000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

-- MAP_ID = 104 (HR_EMP_HISTORY_STACKED_F)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO HR_EMP_HISTORY_STACKED_F (SOURCE_TAG, TRACK_TYPE, EVENT_END_DATE, HISTORY_GAP_DAYS, DD, EE_SIGNAL, TRACK_SEQ, DEPARTMENT_ID, EMPLOYEE_ID, EVENT_DATE, JOB_ID, CURRENT_SALARY)
SELECT ''EMPLOYEES'' AS SOURCE_TAG, ''CURRENT_TRACK'' AS TRACK_TYPE, CAST(NULL AS DATE) AS EVENT_END_DATE, CAST(NULL AS NUMBER) AS HISTORY_GAP_DAYS, CAST(NULL AS VARCHAR2(100)) AS DD, CAST(NULL AS VARCHAR2(50)) AS EE_SIGNAL, ROW_NUMBER() OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE) AS TRACK_SEQ, e.DEPARTMENT_ID, e.EMPLOYEE_ID, e.HIRE_DATE AS EVENT_DATE, e.JOB_ID, e.SALARY AS CURRENT_SALARY FROM EMPLOYEES e
UNION ALL
SELECT ''JOB_HISTORY'' AS SOURCE_TAG, ''HISTORY_TRACK'' AS TRACK_TYPE, jh.END_DATE AS EVENT_END_DATE, TRUNC(NVL(jh.END_DATE, SYSDATE) - jh.START_DATE) AS HISTORY_GAP_DAYS, CAST(NULL AS VARCHAR2(100)) AS DD, CAST(NULL AS VARCHAR2(50)) AS EE_SIGNAL, ROW_NUMBER() OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE) AS TRACK_SEQ, jh.DEPARTMENT_ID, jh.EMPLOYEE_ID, jh.START_DATE AS EVENT_DATE, jh.JOB_ID, CAST(NULL AS NUMBER) AS CURRENT_SALARY FROM JOB_HISTORY jh';
    v_verify := 'SELECT SUM(CASE WHEN src.SOURCE_TAG = ''EMPLOYEES'' THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.SOURCE_TAG = ''EMPLOYEES'' THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.SOURCE_TAG = ''JOB_HISTORY'' THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.SOURCE_TAG = ''JOB_HISTORY'' THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.TRACK_TYPE = ''CURRENT_TRACK'' THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.TRACK_TYPE = ''CURRENT_TRACK'' THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.TRACK_TYPE = ''HISTORY_TRACK'' THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.TRACK_TYPE = ''HISTORY_TRACK'' THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.EVENT_END_DATE IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.EVENT_END_DATE IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.HISTORY_GAP_DAYS IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.HISTORY_GAP_DAYS IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.DD IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.DD IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.EE_SIGNAL IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.EE_SIGNAL IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.TRACK_SEQ IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.TRACK_SEQ IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.DEPARTMENT_ID IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.DEPARTMENT_ID IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.EMPLOYEE_ID IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.EMPLOYEE_ID IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.EVENT_DATE IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.EVENT_DATE IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.JOB_ID IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.JOB_ID IS NULL THEN 1 ELSE NULL END) + 
       SUM(CASE WHEN src.CURRENT_SALARY IS NULL THEN 1 ELSE 0 END) - COUNT(CASE WHEN tgt.CURRENT_SALARY IS NULL THEN 1 ELSE NULL END) AS DIFF
FROM (
  SELECT 
    ''EMPLOYEES'' AS SOURCE_TAG, 
    ''CURRENT_TRACK'' AS TRACK_TYPE, 
    CAST(NULL AS DATE) AS EVENT_END_DATE, 
    CAST(NULL AS NUMBER) AS HISTORY_GAP_DAYS, 
    CAST(NULL AS VARCHAR2(100)) AS DD, 
    CAST(NULL AS VARCHAR2(50)) AS EE_SIGNAL, 
    ROW_NUMBER() OVER (PARTITION BY e.EMPLOYEE_ID ORDER BY e.HIRE_DATE) AS TRACK_SEQ, 
    e.DEPARTMENT_ID, 
    e.EMPLOYEE_ID, 
    e.HIRE_DATE AS EVENT_DATE, 
    e.JOB_ID, 
    e.SALARY AS CURRENT_SALARY 
  FROM EMPLOYEES e
  UNION ALL
  SELECT 
    ''JOB_HISTORY'' AS SOURCE_TAG, 
    ''HISTORY_TRACK'' AS TRACK_TYPE, 
    jh.END_DATE AS EVENT_END_DATE, 
    TRUNC(NVL(jh.END_DATE, SYSDATE) - jh.START_DATE) AS HISTORY_GAP_DAYS, 
    CAST(NULL AS VARCHAR2(100)) AS DD, 
    CAST(NULL AS VARCHAR2(50)) AS EE_SIGNAL, 
    ROW_NUMBER() OVER (PARTITION BY jh.EMPLOYEE_ID ORDER BY jh.START_DATE) AS TRACK_SEQ, 
    jh.DEPARTMENT_ID, 
    jh.EMPLOYEE_ID, 
    jh.START_DATE AS EVENT_DATE, 
    jh.JOB_ID, 
    CAST(NULL AS NUMBER) AS CURRENT_SALARY 
  FROM JOB_HISTORY jh
) src
LEFT JOIN HR_EMP_HISTORY_STACKED_F tgt ON src.EMPLOYEE_ID = tgt.EMPLOYEE_ID AND src.EVENT_DATE = tgt.EVENT_DATE AND src.SOURCE_TAG = tgt.SOURCE_TAG';
    v_correct := NULL;
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        104, 'COMPLEX', '(AA/BB/CC/EE CASE UNION ALL) FROM EMPLOYEES, JOB_HISTORY', 'HR_EMP_HISTORY_STACKED_F',
        'N', 'Y', 104,
        v_mig, v_verify,
        'PASS', 2, v_correct, 'N',
        TO_TIMESTAMP('2026-04-15 21:25:20.500000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 15, 2,
        TO_TIMESTAMP('2026-04-15 10:18:13.835000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

-- MAP_ID = 105 (HR_EMP_TYPECAST_AUDIT)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO HR_EMP_TYPECAST_AUDIT (
  JOB_RANGE_CHECK,
  CAST_QUALITY_STATUS,
  MAX_SALARY_DECIMAL,
  MIN_SALARY_DECIMAL,
  COMMISSION_TXT,
  EMP_HASH_KEY,
  DEPARTMENT_ID_TXT,
  EMPLOYEE_ID_TXT,
  HIRE_DATE_YYYYMMDD,
  JOB_ID_TXT,
  SALARY_TXT,
  MAX_SALARY_TXT,
  MIN_SALARY_TXT,
  HIRE_DATE_ROUNDTRIP,
  SALARY_NUM
)
SELECT 
  CASE WHEN CAST(j.MIN_SALARY AS NUMBER(12,2)) IS NULL OR CAST(j.MAX_SALARY AS NUMBER(12,2)) IS NULL THEN ''JOB_RANGE_MISSING'' WHEN CAST(j.MIN_SALARY AS NUMBER(12,2)) > CAST(j.MAX_SALARY AS NUMBER(12,2)) THEN ''JOB_RANGE_INVALID'' ELSE ''JOB_RANGE_OK'' END AS JOB_RANGE_CHECK,
  CASE WHEN TO_NUMBER(TO_CHAR(e.SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,''), ''9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') IS NULL THEN ''NUM_CAST_FAIL'' WHEN TO_DATE(TO_CHAR(e.HIRE_DATE, ''YYYYMMDD''), ''YYYYMMDD'') IS NULL THEN ''DATE_CAST_FAIL'' ELSE ''OK'' END AS CAST_QUALITY_STATUS,
  CAST(j.MAX_SALARY AS NUMBER(12,2)) AS MAX_SALARY_DECIMAL,
  CAST(j.MIN_SALARY AS NUMBER(12,2)) AS MIN_SALARY_DECIMAL,
  NVL(TO_CHAR(e.COMMISSION_PCT, ''FM0D99'', ''NLS_NUMERIC_CHARACTERS=.,''), ''0.00'') AS COMMISSION_TXT,
  TO_CHAR(ORA_HASH(TO_CHAR(e.EMPLOYEE_ID) || '':'' || TO_CHAR(e.HIRE_DATE, ''YYYYMMDD'') || '':'' || TO_CHAR(e.JOB_ID))) AS EMP_HASH_KEY,
  TO_CHAR(e.DEPARTMENT_ID) AS DEPARTMENT_ID_TXT,
  TO_CHAR(e.EMPLOYEE_ID) AS EMPLOYEE_ID_TXT,
  TO_CHAR(e.HIRE_DATE, ''YYYYMMDD'') AS HIRE_DATE_YYYYMMDD,
  TO_CHAR(e.JOB_ID) AS JOB_ID_TXT,
  TO_CHAR(e.SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS SALARY_TXT,
  TO_CHAR(j.MAX_SALARY) AS MAX_SALARY_TXT,
  TO_CHAR(j.MIN_SALARY) AS MIN_SALARY_TXT,
  TO_DATE(TO_CHAR(e.HIRE_DATE, ''YYYYMMDD''), ''YYYYMMDD'') AS HIRE_DATE_ROUNDTRIP,
  TO_NUMBER(TO_CHAR(e.SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,''), ''9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS SALARY_NUM
FROM EMPLOYEES e
LEFT JOIN JOBS j ON j.JOB_ID = e.JOB_ID;';
    v_verify := 'SELECT SUM(CASE WHEN src.JOB_RANGE_CHECK <> tgt.JOB_RANGE_CHECK THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.CAST_QUALITY_STATUS <> tgt.CAST_QUALITY_STATUS THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.MAX_SALARY_DECIMAL <> tgt.MAX_SALARY_DECIMAL THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.MIN_SALARY_DECIMAL <> tgt.MIN_SALARY_DECIMAL THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.COMMISSION_TXT <> tgt.COMMISSION_TXT THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.EMP_HASH_KEY <> tgt.EMP_HASH_KEY THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.DEPARTMENT_ID_TXT <> tgt.DEPARTMENT_ID_TXT THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.EMPLOYEE_ID_TXT <> tgt.EMPLOYEE_ID_TXT THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.HIRE_DATE_YYYYMMDD <> tgt.HIRE_DATE_YYYYMMDD THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.JOB_ID_TXT <> tgt.JOB_ID_TXT THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.SALARY_TXT <> tgt.SALARY_TXT THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.MAX_SALARY_TXT <> tgt.MAX_SALARY_TXT THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.MIN_SALARY_TXT <> tgt.MIN_SALARY_TXT THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.HIRE_DATE_ROUNDTRIP <> tgt.HIRE_DATE_ROUNDTRIP THEN 1 ELSE 0 END) +
       SUM(CASE WHEN src.SALARY_NUM <> tgt.SALARY_NUM THEN 1 ELSE 0 END) AS DIFF
FROM (
  SELECT 
    CASE WHEN CAST(j.MIN_SALARY AS NUMBER(12,2)) IS NULL OR CAST(j.MAX_SALARY AS NUMBER(12,2)) IS NULL THEN ''JOB_RANGE_MISSING'' WHEN CAST(j.MIN_SALARY AS NUMBER(12,2)) > CAST(j.MAX_SALARY AS NUMBER(12,2)) THEN ''JOB_RANGE_INVALID'' ELSE ''JOB_RANGE_OK'' END AS JOB_RANGE_CHECK,
    CASE WHEN TO_NUMBER(TO_CHAR(e.SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,''), ''9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') IS NULL THEN ''NUM_CAST_FAIL'' WHEN TO_DATE(TO_CHAR(e.HIRE_DATE, ''YYYYMMDD''), ''YYYYMMDD'') IS NULL THEN ''DATE_CAST_FAIL'' ELSE ''OK'' END AS CAST_QUALITY_STATUS,
    CAST(j.MAX_SALARY AS NUMBER(12,2)) AS MAX_SALARY_DECIMAL,
    CAST(j.MIN_SALARY AS NUMBER(12,2)) AS MIN_SALARY_DECIMAL,
    NVL(TO_CHAR(e.COMMISSION_PCT, ''FM0D99'', ''NLS_NUMERIC_CHARACTERS=.,''), ''0.00'') AS COMMISSION_TXT,
    TO_CHAR(ORA_HASH(TO_CHAR(e.EMPLOYEE_ID) || '':'' || TO_CHAR(e.HIRE_DATE, ''YYYYMMDD'') || '':'' || TO_CHAR(e.JOB_ID))) AS EMP_HASH_KEY,
    TO_CHAR(e.DEPARTMENT_ID) AS DEPARTMENT_ID_TXT,
    TO_CHAR(e.EMPLOYEE_ID) AS EMPLOYEE_ID_TXT,
    TO_CHAR(e.HIRE_DATE, ''YYYYMMDD'') AS HIRE_DATE_YYYYMMDD,
    TO_CHAR(e.JOB_ID) AS JOB_ID_TXT,
    TO_CHAR(e.SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS SALARY_TXT,
    TO_CHAR(j.MAX_SALARY) AS MAX_SALARY_TXT,
    TO_CHAR(j.MIN_SALARY) AS MIN_SALARY_TXT,
    TO_DATE(TO_CHAR(e.HIRE_DATE, ''YYYYMMDD''), ''YYYYMMDD'') AS HIRE_DATE_ROUNDTRIP,
    TO_NUMBER(TO_CHAR(e.SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,''), ''9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS SALARY_NUM
  FROM EMPLOYEES e
  LEFT JOIN JOBS j ON j.JOB_ID = e.JOB_ID
) src,
(
  SELECT 
    JOB_RANGE_CHECK,
    CAST_QUALITY_STATUS,
    MAX_SALARY_DECIMAL,
    MIN_SALARY_DECIMAL,
    COMMISSION_TXT,
    EMP_HASH_KEY,
    DEPARTMENT_ID_TXT,
    EMPLOYEE_ID_TXT,
    HIRE_DATE_YYYYMMDD,
    JOB_ID_TXT,
    SALARY_TXT,
    MAX_SALARY_TXT,
    MIN_SALARY_TXT,
    HIRE_DATE_ROUNDTRIP,
    SALARY_NUM
  FROM HR_EMP_TYPECAST_AUDIT
) tgt
WHERE src.EMPLOYEE_ID_TXT = tgt.EMPLOYEE_ID_TXT;';
    v_correct := NULL;
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        105, 'COMPLEX', 'EMPLOYEES e LEFT JOIN JOBS j ON j.JOB_ID=e.JOB_ID', 'HR_EMP_TYPECAST_AUDIT',
        'N', 'Y', 105,
        v_mig, v_verify,
        'PASS', 2, v_correct, 'N',
        TO_TIMESTAMP('2026-04-15 21:25:42.141000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 20, 2,
        TO_TIMESTAMP('2026-04-15 10:18:13.842000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

-- MAP_ID = 106 (HR_DEPT_TYPECAST_AUDIT)
DECLARE
    v_mig     CLOB;
    v_verify  CLOB;
    v_correct CLOB;
    v_ddl     CLOB;
BEGIN
    v_mig := 'INSERT INTO HR_DEPT_TYPECAST_AUDIT (
  DEPARTMENT_ID_LPAD,
  DEPARTMENT_NAME,
  DEPARTMENT_ID_TXT,
  DEPT_PAY_BAND,
  DEPT_SIZE_BAND,
  AVG_SALARY_NUM,
  EMP_COUNT_NUM,
  DEPT_HASH_KEY,
  SNAP_DATE_YYYYMMDD,
  AVG_SALARY_TXT,
  EMP_COUNT_TXT,
  MAX_SALARY_TXT,
  MIN_SALARY_TXT,
  TOTAL_SALARY_TXT,
  SNAP_DATE
)
SELECT 
  LPAD(TO_CHAR(dept_data.DEPARTMENT_ID), 6, ''0'') AS DEPARTMENT_ID_LPAD,
  dept_data.DEPARTMENT_NAME AS DEPARTMENT_NAME,
  TO_CHAR(dept_data.DEPARTMENT_ID) AS DEPARTMENT_ID_TXT,
  CASE 
    WHEN dept_agg.AVG_SALARY IS NULL THEN ''N/A''
    WHEN dept_agg.AVG_SALARY >= 12000 THEN ''HIGH_PAY''
    WHEN dept_agg.AVG_SALARY >= 7000 THEN ''MID_PAY''
    ELSE ''LOW_PAY''
  END AS DEPT_PAY_BAND,
  CASE 
    WHEN dept_agg.EMP_COUNT = 0 THEN ''EMPTY''
    WHEN dept_agg.EMP_COUNT >= 10 THEN ''LARGE''
    WHEN dept_agg.EMP_COUNT >= 5 THEN ''MEDIUM''
    ELSE ''SMALL''
  END AS DEPT_SIZE_BAND,
  CAST(dept_agg.AVG_SALARY AS NUMBER(12,2)) AS AVG_SALARY_NUM,
  CAST(dept_agg.EMP_COUNT AS NUMBER(10,0)) AS EMP_COUNT_NUM,
  TO_CHAR(ORA_HASH(TO_CHAR(dept_data.DEPARTMENT_ID) || '':'' || TO_CHAR(NVL(dept_agg.EMP_COUNT,0)) || '':'' || TO_CHAR(NVL(dept_agg.TOTAL_SALARY,0)))) AS DEPT_HASH_KEY,
  TO_CHAR(SYSDATE, ''YYYYMMDD'') AS SNAP_DATE_YYYYMMDD,
  TO_CHAR(dept_agg.AVG_SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS AVG_SALARY_TXT,
  TO_CHAR(dept_agg.EMP_COUNT) AS EMP_COUNT_TXT,
  TO_CHAR(dept_agg.MAX_SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS MAX_SALARY_TXT,
  TO_CHAR(dept_agg.MIN_SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS MIN_SALARY_TXT,
  TO_CHAR(dept_agg.TOTAL_SALARY, ''FM9999999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS TOTAL_SALARY_TXT,
  TO_DATE(TO_CHAR(SYSDATE, ''YYYYMMDD''), ''YYYYMMDD'') AS SNAP_DATE
FROM (
  SELECT 
    d.DEPARTMENT_ID, 
    d.DEPARTMENT_NAME
  FROM DEPARTMENTS d
) dept_data
LEFT JOIN (
  SELECT 
    d.DEPARTMENT_ID,
    AVG(e.SALARY) AS AVG_SALARY,
    COUNT(e.EMPLOYEE_ID) AS EMP_COUNT,
    MAX(e.SALARY) AS MAX_SALARY,
    MIN(e.SALARY) AS MIN_SALARY,
    SUM(e.SALARY) AS TOTAL_SALARY
  FROM DEPARTMENTS d
  LEFT JOIN EMPLOYEES e ON e.DEPARTMENT_ID = d.DEPARTMENT_ID
  GROUP BY d.DEPARTMENT_ID
) dept_agg ON dept_data.DEPARTMENT_ID = dept_agg.DEPARTMENT_ID;';
    v_verify := 'SELECT SUM(CASE WHEN src.DEPARTMENT_ID_LPAD <> tgt.DEPARTMENT_ID_LPAD THEN 1 ELSE 0 END +
       CASE WHEN src.DEPARTMENT_NAME <> tgt.DEPARTMENT_NAME THEN 1 ELSE 0 END +
       CASE WHEN src.DEPARTMENT_ID_TXT <> tgt.DEPARTMENT_ID_TXT THEN 1 ELSE 0 END +
       CASE WHEN src.DEPT_PAY_BAND <> tgt.DEPT_PAY_BAND THEN 1 ELSE 0 END +
       CASE WHEN src.DEPT_SIZE_BAND <> tgt.DEPT_SIZE_BAND THEN 1 ELSE 0 END +
       CASE WHEN src.AVG_SALARY_NUM <> tgt.AVG_SALARY_NUM THEN 1 ELSE 0 END +
       CASE WHEN src.EMP_COUNT_NUM <> tgt.EMP_COUNT_NUM THEN 1 ELSE 0 END +
       CASE WHEN src.DEPT_HASH_KEY <> tgt.DEPT_HASH_KEY THEN 1 ELSE 0 END +
       CASE WHEN src.SNAP_DATE_YYYYMMDD <> tgt.SNAP_DATE_YYYYMMDD THEN 1 ELSE 0 END +
       CASE WHEN src.AVG_SALARY_TXT <> tgt.AVG_SALARY_TXT THEN 1 ELSE 0 END +
       CASE WHEN src.EMP_COUNT_TXT <> tgt.EMP_COUNT_TXT THEN 1 ELSE 0 END +
       CASE WHEN src.MAX_SALARY_TXT <> tgt.MAX_SALARY_TXT THEN 1 ELSE 0 END +
       CASE WHEN src.MIN_SALARY_TXT <> tgt.MIN_SALARY_TXT THEN 1 ELSE 0 END +
       CASE WHEN src.TOTAL_SALARY_TXT <> tgt.TOTAL_SALARY_TXT THEN 1 ELSE 0 END +
       CASE WHEN src.SNAP_DATE <> tgt.SNAP_DATE THEN 1 ELSE 0 END) AS DIFF
FROM (
  SELECT 
    LPAD(TO_CHAR(dept_data.DEPARTMENT_ID), 6, ''0'') AS DEPARTMENT_ID_LPAD,
    dept_data.DEPARTMENT_NAME AS DEPARTMENT_NAME,
    TO_CHAR(dept_data.DEPARTMENT_ID) AS DEPARTMENT_ID_TXT,
    CASE 
      WHEN dept_agg.AVG_SALARY IS NULL THEN ''N/A''
      WHEN dept_agg.AVG_SALARY >= 12000 THEN ''HIGH_PAY''
      WHEN dept_agg.AVG_SALARY >= 7000 THEN ''MID_PAY''
      ELSE ''LOW_PAY''
    END AS DEPT_PAY_BAND,
    CASE 
      WHEN dept_agg.EMP_COUNT = 0 THEN ''EMPTY''
      WHEN dept_agg.EMP_COUNT >= 10 THEN ''LARGE''
      WHEN dept_agg.EMP_COUNT >= 5 THEN ''MEDIUM''
      ELSE ''SMALL''
    END AS DEPT_SIZE_BAND,
    CAST(dept_agg.AVG_SALARY AS NUMBER(12,2)) AS AVG_SALARY_NUM,
    CAST(dept_agg.EMP_COUNT AS NUMBER(10,0)) AS EMP_COUNT_NUM,
    TO_CHAR(ORA_HASH(TO_CHAR(dept_data.DEPARTMENT_ID) || '':'' || TO_CHAR(NVL(dept_agg.EMP_COUNT,0)) || '':'' || TO_CHAR(NVL(dept_agg.TOTAL_SALARY,0)))) AS DEPT_HASH_KEY,
    TO_CHAR(SYSDATE, ''YYYYMMDD'') AS SNAP_DATE_YYYYMMDD,
    TO_CHAR(dept_agg.AVG_SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS AVG_SALARY_TXT,
    TO_CHAR(dept_agg.EMP_COUNT) AS EMP_COUNT_TXT,
    TO_CHAR(dept_agg.MAX_SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS MAX_SALARY_TXT,
    TO_CHAR(dept_agg.MIN_SALARY, ''FM9999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS MIN_SALARY_TXT,
    TO_CHAR(dept_agg.TOTAL_SALARY, ''FM9999999990D00'', ''NLS_NUMERIC_CHARACTERS=.,'') AS TOTAL_SALARY_TXT,
    TO_DATE(TO_CHAR(SYSDATE, ''YYYYMMDD''), ''YYYYMMDD'') AS SNAP_DATE
  FROM (
    SELECT 
      d.DEPARTMENT_ID, 
      d.DEPARTMENT_NAME
    FROM DEPARTMENTS d
  ) dept_data
  LEFT JOIN (
    SELECT 
      d.DEPARTMENT_ID,
      AVG(e.SALARY) AS AVG_SALARY,
      COUNT(e.EMPLOYEE_ID) AS EMP_COUNT,
      MAX(e.SALARY) AS MAX_SALARY,
      MIN(e.SALARY) AS MIN_SALARY,
      SUM(e.SALARY) AS TOTAL_SALARY
    FROM DEPARTMENTS d
    LEFT JOIN EMPLOYEES e ON e.DEPARTMENT_ID = d.DEPARTMENT_ID
    GROUP BY d.DEPARTMENT_ID
  ) dept_agg ON dept_data.DEPARTMENT_ID = dept_agg.DEPARTMENT_ID
) src
FULL OUTER JOIN HR_DEPT_TYPECAST_AUDIT tgt ON src.DEPARTMENT_ID_LPAD = tgt.DEPARTMENT_ID_LPAD AND src.DEPARTMENT_NAME = tgt.DEPARTMENT_NAME;';
    v_correct := NULL;
    v_ddl := NULL;
    INSERT INTO NEXT_MIG_INFO (
        MAP_ID, MAP_TYPE, FR_TABLE, TO_TABLE, USE_YN, TARGET_YN, PRIORITY,
        MIG_SQL, VERIFY_SQL, STATUS, BATCH_CNT, CORRECT_SQL, USER_EDITED,
        UPD_TS, ELAPSED_SECONDS, RETRY_COUNT, CREATED_AT, DDL_SQL
    ) VALUES (
        106, 'COMPLEX', 'DEPARTMENTS d LEFT JOIN EMPLOYEES e ON e.DEPARTMENT_ID=d.DEPARTMENT_ID', 'HR_DEPT_TYPECAST_AUDIT',
        'N', 'Y', 106,
        v_mig, v_verify,
        'PASS', 4, v_correct, 'N',
        TO_TIMESTAMP('2026-04-15 21:51:52.518000', 'YYYY-MM-DD HH24:MI:SS.FF6'), 28, 3,
        TO_TIMESTAMP('2026-04-15 10:18:13.849000', 'YYYY-MM-DD HH24:MI:SS.FF6'), v_ddl
    );
END;
/

